class Solution {
    public boolean[] canMakePalindromeQueries(String s, int[][] queries) {
        boolean[] answer = new boolean[queries.length];
        for (int i = 0; i < queries.length; i++) {
            int a = queries[i][0], b = queries[i][1], c = queries[i][2], d = queries[i][3];
            String left = s.substring(a, b + 1), right = s.substring(c, d + 1);
            if (left.equals(new StringBuilder(left).reverse().toString()) && right.equals(new StringBuilder(right).reverse().toString())) {
                answer[i] = true;
            } else {
                answer[i] = false;
            }
        }
        return answer;
    }
}

